#include<bits/stdc++.h>
using namespace std;
const int MAXN=1e5+10;
int a[MAXN],f[MAXN][20];
int main()
{
	ios::sync_with_stdio(false);
	cin.tie(0);
	cout.tie(0);
	int n,m;
	cin>>n>>m;
	for(int i=1;i<=n;i++){
		cin>>a[i];
		f[i][0]=a[i];
	}
	for(int j=1;j<=20;j++){
		for(int i=1;i+(1<<j)-1<=n;i++){
			f[i][j]=max(f[i][j-1],f[i+(1<<(j-1))][j-1]);
		}
	}
	for(int i=1;i<=m;i++){
		int l,r;
		cin>>l>>r;
		if(l>r)swap(l,r);
		int len=__lg(r-l+1);
		int ans=max(f[l][len],f[r-(1<<len)+1][len]);
		cout<<ans<<"\n";
	}
}
